import React from 'react';
import { useState } from 'react';
import { submitQuote } from '../../services/api';

const Hero = ({ content = {} }) => {
  const {
    title = 'Assurance Décennale Électricien',
    subtitle = 'Comparez et souscrivez votre assurance décennale en quelques clics',
    ctaText = 'Obtenir mon devis'
  } = content;

  const [formData, setFormData] = useState({
    nom: '',
    prenom: '',
    tele: '',
    email: '',
    activite: '',
    raisonSociale: ''
  });
  const [loading, setLoading] = useState(false);
  const [success, setSuccess] = useState(false);
  const [error, setError] = useState(null);

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError(null);

    try {
      await submitQuote(formData);
      setSuccess(true);
    } catch (err) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  };

  return (
    <section className="bg-yellow-500 py-16">
      <div className="container mx-auto px-4">
        <div className="grid lg:grid-cols-2 gap-12 items-center">
          <div className="text-white">
            <h1 className="text-4xl md:text-5xl font-bold mb-4">{title}</h1>
            <p className="text-xl mb-8 text-yellow-100">{subtitle}</p>
            <div className="space-y-3">
              <div className="flex items-center space-x-3">
                <i className="fas fa-check-circle text-2xl"></i>
                <span>Devis gratuit et sans engagement</span>
              </div>
              <div className="flex items-center space-x-3">
                <i className="fas fa-check-circle text-2xl"></i>
                <span>Comparaison des meilleures garanties</span>
              </div>
              <div className="flex items-center space-x-3">
                <i className="fas fa-check-circle text-2xl"></i>
                <span>Expertise spécialisée bâtiment</span>
              </div>
            </div>
          </div>

          <div className="bg-white rounded-2xl p-8 shadow-xl">
            {success ? (
              <div className="text-center py-8">
                <div className="w-16 h-16 bg-green-500 rounded-full flex items-center justify-center mx-auto mb-4">
                  <i className="fas fa-check text-white text-2xl"></i>
                </div>
                <h2 className="text-2xl font-bold text-gray-800 mb-2">Merci !</h2>
                <p className="text-gray-600">Votre demande a été envoyée. Un expert vous contactera rapidement.</p>
              </div>
            ) : (
              <form onSubmit={handleSubmit} className="space-y-4">
                <h2 className="text-xl font-bold text-gray-800 mb-4">Demandez votre devis</h2>

                {error && (
                  <div className="bg-red-100 text-red-700 px-4 py-2 rounded">{error}</div>
                )}

                <div className="grid md:grid-cols-2 gap-4">
                  <input
                    type="text"
                    name="nom"
                    value={formData.nom}
                    onChange={handleChange}
                    placeholder="Nom *"
                    className="w-full px-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-yellow-500 focus:border-yellow-500 outline-none"
                    required
                  />
                  <input
                    type="text"
                    name="prenom"
                    value={formData.prenom}
                    onChange={handleChange}
                    placeholder="Prénom *"
                    className="w-full px-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-yellow-500 focus:border-yellow-500 outline-none"
                    required
                  />
                </div>

                <input
                  type="tel"
                  name="tele"
                  value={formData.tele}
                  onChange={handleChange}
                  placeholder="Téléphone *"
                  className="w-full px-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-yellow-500 focus:border-yellow-500 outline-none"
                  required
                />

                <input
                  type="email"
                  name="email"
                  value={formData.email}
                  onChange={handleChange}
                  placeholder="Email *"
                  className="w-full px-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-yellow-500 focus:border-yellow-500 outline-none"
                  required
                />

                <select
                  name="activite"
                  value={formData.activite}
                  onChange={handleChange}
                  className="w-full px-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-yellow-500 focus:border-yellow-500 outline-none"
                  required
                >
                  <option value="">Statut juridique *</option>
                  <option value="auto-entrepreneur">Auto-entrepreneur</option>
                  <option value="ei">Entreprise Individuelle</option>
                  <option value="eurl">EURL</option>
                  <option value="sarl">SARL</option>
                  <option value="sas">SAS</option>
                </select>

                <input
                  type="text"
                  name="raisonSociale"
                  value={formData.raisonSociale}
                  onChange={handleChange}
                  placeholder="Chiffre d'affaires annuel"
                  className="w-full px-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-yellow-500 focus:border-yellow-500 outline-none"
                />

                <button
                  type="submit"
                  disabled={loading}
                  className="w-full bg-yellow-500 text-white font-bold py-4 rounded-lg hover:bg-yellow-600 transition-colors disabled:opacity-50"
                >
                  {loading ? 'Envoi...' : ctaText}
                </button>
              </form>
            )}
          </div>
        </div>
      </div>
    </section>
  );
};

export default Hero;
